// Parsear respuesta de Supabase
const respuesta = $input.item.json;

// Si es array, usar directamente; si es objeto, convertirlo a array
let observaciones = Array.isArray(respuesta) ? respuesta : [respuesta];

// Filtrar observaciones válidas (con email)
observaciones = observaciones.filter(obs => 
  obs.responsable_implementacion_user && 
  obs.responsable_implementacion_user.email
);

if (observaciones.length === 0) {
  return [];
}

// Preparar datos para cada observación
return observaciones.map(obs => ({
  json: {
    observacion_id: obs.id,
    auditoria_id: obs.auditoria_id,
    numero_observacion: obs.numero_observacion || 0,
    titulo: obs.titulo_observacion || 'Sin título',
    descripcion: obs.descripcion_observacion || 'Sin descripción',
    fecha_fin: obs.fecha_fin,
    dias_restantes: obs.dias_restantes || 0,
    estado_observacion: obs.estado_observacion || 'EN_PROCESO',
    responsable_id: obs.responsable_implementacion,
    responsable_nombre: obs.responsable_implementacion_user?.full_name || 'Responsable',
    responsable_email: obs.responsable_implementacion_user?.email || '',
    auditoria_nombre: obs.auditoria?.nombre || 'Auditoría',
    auditoria_estado: obs.auditoria?.estado || 'EN_PROCESO'
  }
}));

// Generar HTML del correo recordatorio
const obs = $json;

const fechaLimite = obs.fecha_fin ? new Date(obs.fecha_fin).toLocaleDateString('es-ES', {
  year: 'numeric',
  month: 'long',
  day: 'numeric'
}) : 'No definida';

const diasRestantes = obs.dias_restantes || 0;
const colorAlerta = diasRestantes <= 30 ? '#dc2626' : diasRestantes <= 60 ? '#f59e0b' : '#2563eb';

const html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; margin: 0; padding: 0; }
    .container { max-width: 600px; margin: 0 auto; padding: 20px; background: #f9fafb; }
    .header { background: ${colorAlerta}; color: white; padding: 20px; border-radius: 8px 8px 0 0; text-align: center; }
    .content { background: white; padding: 20px; border-radius: 0 0 8px 8px; }
    .alert { background: #fef3c7; border-left: 4px solid #f59e0b; padding: 15px; margin: 15px 0; border-radius: 4px; }
    .info-box { background: #f9fafb; padding: 15px; margin: 15px 0; border-radius: 4px; border: 1px solid #e5e7eb; }
    .info-box h3 { margin-top: 0; color: #1f2937; }
    .info-box p { margin: 8px 0; }
    .badge { display: inline-block; padding: 4px 12px; border-radius: 12px; font-size: 12px; font-weight: bold; }
    .badge-urgente { background: #fee2e2; color: #991b1b; }
    .badge-proximo { background: #fef3c7; color: #92400e; }
    .badge-normal { background: #dbeafe; color: #1e40af; }
    .footer { text-align: center; margin-top: 20px; color: #6b7280; font-size: 12px; padding-top: 20px; border-top: 1px solid #e5e7eb; }
    .button { display: inline-block; padding: 12px 24px; background: #2563eb; color: white; text-decoration: none; border-radius: 6px; margin-top: 15px; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1 style="margin: 0;">⏰ Recordatorio de Cumplimiento</h1>
    </div>
    <div class="content">
      <p>Estimado/a <strong>${obs.responsable_nombre}</strong>,</p>

      <div class="alert">
        <strong>⚠️ IMPORTANTE:</strong> Tienes una observación de auditoría con fecha de cumplimiento próxima.
      </div>

      <div class="info-box">
        <h3>📋 Detalles de la Observación</h3>
        <p><strong>Auditoría:</strong> ${obs.auditoria_nombre}</p>
        <p><strong>Observación N°:</strong> ${obs.numero_observacion}</p>
        <p><strong>Título:</strong> ${obs.titulo}</p>
        <p><strong>Descripción:</strong> ${obs.descripcion}</p>
        <p><strong>Fecha Límite:</strong> <strong style="color: ${colorAlerta};">${fechaLimite}</strong></p>
        <p><strong>Días Restantes:</strong> <span class="badge ${diasRestantes <= 30 ? 'badge-urgente' : diasRestantes <= 60 ? 'badge-proximo' : 'badge-normal'}">${diasRestantes} días</span></p>
        <p><strong>Estado Actual:</strong> ${obs.estado_observacion}</p>
      </div>

      <p><strong>📌 Acciones Requeridas:</strong></p>
      <ul>
        <li>Registrar el <strong>porcentaje de avance</strong> en el sistema</li>
        <li>Subir las <strong>evidencias</strong> correspondientes</li>
        <li>Completar la implementación antes de la fecha límite</li>
      </ul>

      <p style="text-align: center;">
        <a href="#" class="button">Acceder al Sistema</a>
      </p>

      <p style="margin-top: 20px; font-size: 14px; color: #6b7280;">
        Este recordatorio se envía automáticamente cuando una observación tiene vencimiento en los próximos 3 meses.
      </p>
    </div>
    <div class="footer">
      <p>Este es un correo automático del Sistema de Auditoría.<br>No responder a este mensaje.</p>
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    ...obs,
    html_content: html,
    subject: `⏰ Recordatorio: Observación ${obs.numero_observacion} - ${obs.auditoria_nombre} (${diasRestantes} días restantes)`
  }
}];
